// ---- model group members ----

// ReplaceMembers deletes all existing members for a group and inserts the new
// list. The caller must provide members with priority already set in order.
// This runs in a single transaction for atomicity.
func (r *PostgresRepo) ReplaceMembers(ctx context.Context, groupID int64, members []*domain.GroupMember) error {
	tx, err := r.pool.Begin(ctx)
	if err != nil {
		return err
	}
	defer tx.Rollback(ctx)

	q := llmproviderdb.New(tx)

	if err := q.ReplaceMembers(ctx, groupID); err != nil {
		return err
	}

	for _, m := range members {
		if err := q.InsertMember(ctx, llmproviderdb.InsertMemberParams{
			GroupID:    groupID,
			ProviderID: m.ProviderID,
			Model:      m.Model,
			Priority:   m.Priority,
		}); err != nil {
			return err
		}
	}

	return tx.Commit(ctx)
}

// ListMembersByGroupID returns all members of a group joined with provider info,
// ordered by priority ASC.
func (r *PostgresRepo) ListMembersByGroupID(ctx context.Context, groupID int64) ([]*domain.GroupMember, error) {
	rows, err := r.q.ListMembersByGroupID(ctx, groupID)
	if err != nil {
		return nil, err
	}
	out := make([]*domain.GroupMember, 0, len(rows))
	for _, row := range rows {
		out = append(out, memberFromListRow(row))
	}
	return out, nil
}

// GetMemberByID returns a single member by its primary key.
func (r *PostgresRepo) GetMemberByID(ctx context.Context, id int64) (*domain.GroupMember, error) {
	row, err := r.q.GetMemberByID(ctx, id)
	if err != nil {
		if errors.Is(err, pgx.ErrNoRows) {
			return nil, domain.ErrGroupMemberNotFound
		}
		return nil, err
	}
	return memberFromGetRow(row), nil
}

// UpdateMemberHealth applies a HealthPatch to a single member row.
// Each field in the patch is only applied when non-nil (or for
// auto_disabled_until, when the null-flag is set).
func (r *PostgresRepo) UpdateMemberHealth(ctx context.Context, id int64, patch domain.HealthPatch) error {
	params := llmproviderdb.UpdateMemberHealthParams{ID: id}

	if patch.ManualDisabled != nil {
		params.ManualDisabled = pgtype.Bool{Bool: *patch.ManualDisabled, Valid: true}
	}
	if patch.AutoDisabledUntil != nil {
		params.AutoDisabledUntil = pgtype.Timestamptz{Time: *patch.AutoDisabledUntil, Valid: true}
	} else if patch.AutoDisabledUntil == nil && patch.BackoffStep != nil {
		// When AutoDisabledUntil is nil in the patch AND BackoffStep is being set,
		// we interpret this as "clear the auto-disabled state" (e.g. on success or manual enable).
		// The caller explicitly passes nil for AutoDisabledUntil to signal clearing.
		params.AutoDisabledUntilNull = pgtype.Bool{Bool: true, Valid: true}
	}
	if patch.BackoffStep != nil {
		params.BackoffStep = pgtype.Int4{Int32: *patch.BackoffStep, Valid: true}
	}
	if patch.LastFailureAt != nil {
		params.LastFailureAt = pgtype.Timestamptz{Time: *patch.LastFailureAt, Valid: true}
	}
	if patch.LastFailureMsg != nil {
		params.LastFailureMsg = pgtype.Text{String: *patch.LastFailureMsg, Valid: true}
	}
	if patch.LastSuccessAt != nil {
		params.LastSuccessAt = pgtype.Timestamptz{Time: *patch.LastSuccessAt, Valid: true}
	}
	if patch.LastCheckedAt != nil {
		params.LastCheckedAt = pgtype.Timestamptz{Time: *patch.LastCheckedAt, Valid: true}
	}

	n, err := r.q.UpdateMemberHealth(ctx, params)
	if err != nil {
		return err
	}
	if n == 0 {
		return domain.ErrGroupMemberNotFound
	}
	return nil
}

