// ---- llm models ----

// CreateModel inserts a new llm_models row. Returns ErrModelNameConflict on
// unique violation (name already taken, including cross-group conflict).
func (r *PostgresRepo) CreateModel(ctx context.Context, m *domain.ModelDefinition) (*domain.ModelDefinition, error) {
	effortJSON, err := json.Marshal(m.ReasoningEffortMap)
	if err != nil {
		return nil, fmt.Errorf("marshal reasoning_effort_map: %w", err)
	}
	row, err := r.q.CreateModel(ctx, llmproviderdb.CreateModelParams{
		Name:               m.Name,
		DisplayName:        m.DisplayName,
		ContextWindow:      m.ContextWindow,
		MaxOutputTokens:    m.MaxOutputTokens,
		Vision:             m.Vision,
		Reasoning:          m.Reasoning,
		ReasoningEffortMap: effortJSON,
		GroupID:            m.GroupID,
		ActorID:            m.ActorID,
	})
	if err != nil {
		if database.IsUniqueViolation(err) {
			return nil, domain.ErrModelNameConflict
		}
		return nil, err
	}
	return modelFromRow(row), nil
}

// GetModelByName looks up a model by its unique name.
func (r *PostgresRepo) GetModelByName(ctx context.Context, name string) (*domain.ModelDefinition, error) {
	row, err := r.q.GetModelByName(ctx, name)
	if err != nil {
		if errors.Is(err, pgx.ErrNoRows) {
			return nil, domain.ErrModelNotFound
		}
		return nil, err
	}
	return modelFromRow(row), nil
}

// GetModelByID looks up a model by its primary key.
func (r *PostgresRepo) GetModelByID(ctx context.Context, id int64) (*domain.ModelDefinition, error) {
	row, err := r.q.GetModelByID(ctx, id)
	if err != nil {
		if errors.Is(err, pgx.ErrNoRows) {
			return nil, domain.ErrModelNotFound
		}
		return nil, err
	}
	return modelFromRow(row), nil
}

// ListModels returns all models ordered by name.
func (r *PostgresRepo) ListModels(ctx context.Context) ([]*domain.ModelDefinition, error) {
	rows, err := r.q.ListModels(ctx)
	if err != nil {
		return nil, err
	}
	out := make([]*domain.ModelDefinition, 0, len(rows))
	for _, row := range rows {
		out = append(out, modelFromRow(row))
	}
	return out, nil
}

// UpdateModel updates the mutable fields of a model definition.
func (r *PostgresRepo) UpdateModel(ctx context.Context, m *domain.ModelDefinition) (*domain.ModelDefinition, error) {
	effortJSON, err := json.Marshal(m.ReasoningEffortMap)
	if err != nil {
		return nil, fmt.Errorf("marshal reasoning_effort_map: %w", err)
	}
	row, err := r.q.UpdateModel(ctx, llmproviderdb.UpdateModelParams{
		ID:                 m.ID,
		DisplayName:        m.DisplayName,
		ContextWindow:      m.ContextWindow,
		MaxOutputTokens:    m.MaxOutputTokens,
		Vision:             m.Vision,
		Reasoning:          m.Reasoning,
		ReasoningEffortMap: effortJSON,
	})
	if err != nil {
		if errors.Is(err, pgx.ErrNoRows) {
			return nil, domain.ErrModelNotFound
		}
		return nil, err
	}
	return modelFromRow(row), nil
}

// DeleteModel deletes a model definition by id.
func (r *PostgresRepo) DeleteModel(ctx context.Context, id int64) error {
	n, err := r.q.DeleteModel(ctx, id)
	if err != nil {
		return err
	}
	if n == 0 {
		return domain.ErrModelNotFound
	}
	return nil
}

// CountModelsByName returns the number of models with the given name (0 or 1).
func (r *PostgresRepo) CountModelsByName(ctx context.Context, name string) (int64, error) {
	return r.q.CountModelsByName(ctx, name)
}

// ---- row → domain (models) ----

func modelFromRow(r llmproviderdb.LlmModel) *domain.ModelDefinition {
	m := &domain.ModelDefinition{
		ID:                 r.ID,
		Name:               r.Name,
		DisplayName:        r.DisplayName,
		ContextWindow:      r.ContextWindow,
		MaxOutputTokens:    r.MaxOutputTokens,
		Vision:             r.Vision,
		Reasoning:          r.Reasoning,
		ReasoningEffortMap: make(map[string]string),
		GroupID:            r.GroupID,
		ActorID:            r.ActorID,
		CreatedAt:          r.CreatedAt.Time,
		UpdatedAt:          r.UpdatedAt.Time,
	}
	if len(r.ReasoningEffortMap) > 0 {
		if err := json.Unmarshal(r.ReasoningEffortMap, &m.ReasoningEffortMap); err != nil {
			// Should never happen — the DB stores valid JSON.
			m.ReasoningEffortMap = make(map[string]string)
		}
	}
	return m
}

// ---- atomic model+group creation ----

// CreateModelAtomic creates a model, its backing group, and members in a
// single transaction. Returns the created model (with populated ID).
func (r *PostgresRepo) CreateModelAtomic(
	ctx context.Context,
	model *domain.ModelDefinition,
	members []*domain.GroupMember,
) (*domain.ModelDefinition, error) {
	if model.ReasoningEffortMap == nil {
		model.ReasoningEffortMap = make(map[string]string)
	}

	tx, err := r.pool.Begin(ctx)
	if err != nil {
		return nil, err
	}
	defer tx.Rollback(ctx)

	q := llmproviderdb.New(tx)

	// 1. Create the group
	groupRow, err := q.CreateGroup(ctx, llmproviderdb.CreateGroupParams{
		Name:        model.Name,
		Description: "auto-managed by model definition",
		ActorID:     model.ActorID,
	})
	if err != nil {
		if database.IsUniqueViolation(err) {
			return nil, domain.ErrGroupNameConflict
		}
		return nil, fmt.Errorf("create group: %w", err)
	}
	model.GroupID = groupRow.ID

	// 2. Create the model
	effortJSON, err := json.Marshal(model.ReasoningEffortMap)
	if err != nil {
		return nil, fmt.Errorf("marshal reasoning_effort_map: %w", err)
	}
	modelRow, err := q.CreateModel(ctx, llmproviderdb.CreateModelParams{
		Name:               model.Name,
		DisplayName:        model.DisplayName,
		ContextWindow:      model.ContextWindow,
		MaxOutputTokens:    model.MaxOutputTokens,
		Vision:             model.Vision,
		Reasoning:          model.Reasoning,
		ReasoningEffortMap: effortJSON,
		GroupID:            model.GroupID,
		ActorID:            model.ActorID,
	})
	if err != nil {
		if database.IsUniqueViolation(err) {
			return nil, domain.ErrModelNameConflict
		}
		return nil, fmt.Errorf("create model: %w", err)
	}

	// 3. Write members (if any)
	if len(members) > 0 {
		// Delete any existing members first (should be none, but defensive)
		if err := q.ReplaceMembers(ctx, model.GroupID); err != nil {
			return nil, err
		}
		for i, m := range members {
			m.GroupID = model.GroupID
			m.Priority = int32(i)
			if err := q.InsertMember(ctx, llmproviderdb.InsertMemberParams{
				GroupID:    m.GroupID,
				ProviderID: m.ProviderID,
				Model:      m.Model,
				Priority:   m.Priority,
			}); err != nil {
				return nil, err
			}
		}
	}

	if err := tx.Commit(ctx); err != nil {
		return nil, err
	}

	return modelFromRow(modelRow), nil
}

// DeleteModelAtomic deletes a model and its backing group in a single
// transaction. The model row must be deleted first (FK from llm_models
// to llm_model_groups with ON DELETE RESTRICT), then the group (CASCADE
// will clean up members).
func (r *PostgresRepo) DeleteModelAtomic(ctx context.Context, modelID int64) error {
	m, err := r.GetModelByID(ctx, modelID)
	if err != nil {
		return err
	}

	tx, err := r.pool.Begin(ctx)
	if err != nil {
		return err
	}
	defer tx.Rollback(ctx)

	q := llmproviderdb.New(tx)

	// 1. Delete the model first (FK: llm_models.group_id → llm_model_groups.id ON DELETE RESTRICT)
	n, err := q.DeleteModel(ctx, modelID)
	if err != nil {
		return err
	}
	if n == 0 {
		return domain.ErrModelNotFound
	}

	// 2. Delete the group (CASCADE cleans up members). Safe because
	// step 1 already removed the model row that held the RESTRICT FK.
	gn, gErr := q.DeleteGroup(ctx, m.GroupID)
	if gErr != nil {
		return gErr
	}
	if gn == 0 {
		return domain.ErrGroupNotFound
	}

	return tx.Commit(ctx)
}

// UpdateModelWithMembersAtomic updates a model's fields and optionally
// replaces its group members in a single transaction. members==nil means
// "leave members unchanged".
func (r *PostgresRepo) UpdateModelWithMembersAtomic(
	ctx context.Context,
	model *domain.ModelDefinition,
	members []*domain.GroupMember,
) (*domain.ModelDefinition, error) {
	tx, err := r.pool.Begin(ctx)
	if err != nil {
		return nil, err
	}
	defer tx.Rollback(ctx)

	q := llmproviderdb.New(tx)

	effortJSON, err := json.Marshal(model.ReasoningEffortMap)
	if err != nil {
		return nil, fmt.Errorf("marshal reasoning_effort_map: %w", err)
	}
	row, err := q.UpdateModel(ctx, llmproviderdb.UpdateModelParams{
		ID:                 model.ID,
		DisplayName:        model.DisplayName,
		ContextWindow:      model.ContextWindow,
		MaxOutputTokens:    model.MaxOutputTokens,
		Vision:             model.Vision,
		Reasoning:          model.Reasoning,
		ReasoningEffortMap: effortJSON,
	})
	if err != nil {
		if errors.Is(err, pgx.ErrNoRows) {
			return nil, domain.ErrModelNotFound
		}
		return nil, err
	}

	if members != nil {
		if err := q.ReplaceMembers(ctx, model.GroupID); err != nil {
			return nil, err
		}
		for i, m := range members {
			m.GroupID = model.GroupID
			m.Priority = int32(i)
			if err := q.InsertMember(ctx, llmproviderdb.InsertMemberParams{
				GroupID:    m.GroupID,
				ProviderID: m.ProviderID,
				Model:      m.Model,
				Priority:   m.Priority,
			}); err != nil {
				return nil, err
			}
		}
	}

	if err := tx.Commit(ctx); err != nil {
		return nil, err
	}

	return modelFromRow(row), nil
}

